        length = (end - start) // 2
        # 先将整个数据拆分成左右两半子数组，递归去先处理子数组
        left = self.Func(data, copy, start, start+length)
        right = self.Func(data,copy, start+length+1, end)

        # 子数组处理完成后回到这一层，处理两个子数组的合并
        # 两个指针指向两个子数组的末尾
